/**
 * Webhook types and constants for the Infrared SDK.
 *
 * Provides WebhookEndpoint interface, WebhookRegistration type,
 * exception hierarchy, and webhook event constants.
 */

import { InfraredError } from '../errors'

// ---------------------------------------------------------------------------
// Webhook event constants
// ---------------------------------------------------------------------------

export const WEBHOOK_EVENT_RUNNING = 'job.running' as const
export const WEBHOOK_EVENT_SUCCEEDED = 'job.succeeded' as const
export const WEBHOOK_EVENT_FAILED = 'job.failed' as const

// ---------------------------------------------------------------------------
// Exceptions
// ---------------------------------------------------------------------------

/** Base exception for all webhook errors. */
export class WebhookError extends InfraredError {
  constructor(message: string) {
    super(message)
    this.name = 'WebhookError'
  }
}

/** Raised when webhook registration fails. */
export class WebhookRegistrationError extends WebhookError {
  constructor(message: string) {
    super(message)
    this.name = 'WebhookRegistrationError'
  }
}

/** Raised when a webhook endpoint is not found. */
export class WebhookNotFoundError extends WebhookError {
  constructor(message: string) {
    super(message)
    this.name = 'WebhookNotFoundError'
  }
}

// ---------------------------------------------------------------------------
// Data types
// ---------------------------------------------------------------------------

/**
 * Immutable snapshot of a webhook endpoint from the API.
 *
 * The `createdAt` and `updatedAt` fields are optional because the
 * registration response (POST /webhooks) only returns `{id, url, type}`
 * without timestamps, whereas list/get responses include them.
 */
export interface WebhookEndpoint {
  readonly id: string
  readonly url: string
  readonly type: string
  readonly createdAt?: string
  readonly updatedAt?: string
}

/**
 * Build a WebhookEndpoint from an API response dict (camelCase keys).
 *
 * @param data - The raw API response object.
 * @returns An immutable WebhookEndpoint snapshot.
 *
 * @example
 * ```ts
 * const endpoint = webhookEndpointFromResponse({
 *   id: 'ep_123',
 *   url: 'https://example.com/webhook',
 *   type: 'production',
 * })
 * ```
 */
function asStringOrUndefined(v: unknown): string | undefined {
  return typeof v === 'string' ? v : undefined
}

export function webhookEndpointFromResponse(data: Record<string, unknown>): WebhookEndpoint {
  // Defensive narrowing — see jobs/types.ts:jobFromResponse for the rationale.
  // Python's WebhookEndpoint.from_response uses Pydantic which would raise on
  // shape drift; TS uses runtime typeof to surface a coherent error instead
  // of letting `id: undefined as string` silently propagate.
  const id = asStringOrUndefined(data.id)
  const url = asStringOrUndefined(data.url)
  const type = asStringOrUndefined(data.type)
  if (!id || !url || !type) {
    throw new Error(
      `webhookEndpointFromResponse: missing required field(s) ` +
        `id=${typeof data.id}, url=${typeof data.url}, type=${typeof data.type}`,
    )
  }
  return {
    id,
    url,
    type,
    createdAt: asStringOrUndefined(data.createdAt),
    updatedAt: asStringOrUndefined(data.updatedAt),
  }
}

/** Registration request payload for creating a webhook endpoint. */
export interface WebhookRegistration {
  readonly url: string
  readonly type: string
  readonly ip?: string
}
